cssOverrides:
/* Hide account-switch-overlay — position:fixed inset:0 z-index:200 blocks Make select tool even with opacity:0 */
.account-switch-overlay { display: none !important; }
.flow-overlay ~ .mobile-nav__wrapper { display: none !important; }
.flow-overlay--open ~ .mobile-nav__wrapper { display: none !important; }
.account-header__more { display: block !important; }
/* Re-enable avatar border rings inside bottom sheets — fully reconstruct the pseudo-element */
.wise-bottom-sheet .np-circle-border::after {
  content: "" !important;
  display: block !important;
  position: absolute !important;
  top: 0 !important;
  left: 0 !important;
  width: 100% !important;
  height: 100% !important;
  border-radius: 9999px !important;
  box-shadow: inset 0 0 0 1px var(--color-border-neutral) !important;
}

