import { useRef } from 'react';
export function useLiquidGL<T extends HTMLElement = HTMLElement>() { return useRef<T>(null); }
export function refreshLiquidGL() {}

import React from 'react';
interface PinProtectionProps { children: React.ReactNode; onAuthenticated?: () => void; }
export default function PinProtection({ children, onAuthenticated }: PinProtectionProps) {
  React.useEffect(() => { onAuthenticated?.(); }, []);
  return <>{children}</>;
}
